// .ts compiles to .js
const n: number = 1;
// becomes: const n = 1; in output

type Id = string | number;
interface A { x: number }
interface A { y: number } // merged

function parse(input: unknown) {
  if (typeof input === "string") return input.toUpperCase();
}

type Named = { name: string };
type Dated = { at: Date };
type Item = Named & Dated;

function f(x?: string) {
  // x is string | undefined
}

function log(msg: string): void {
  console.log(msg);
}

function greet(name?: string) {
  return `Hi ${name ?? "guest"}`;
}

function add(a = 0, b = 0) {
  return a + b;
}

function max(...n: number[]) {
  return Math.max(...n);
}

class Point {
  constructor(public x: number, public y: number) {}
}

class A {
  private secret = 1;
  protected hook() {}
}

class C {
  readonly id: string;
  constructor(id: string) { this.id = id; }
}

class Animal {
  move() {}
}
class Dog extends Animal {
  bark() {}
}

abstract class Shape {
  abstract area(): number;
}

class B extends A {
  override greet() { return super.greet() + "!"; }
}

class Box {
  private _v = 0;
  get value() { return this._v; }
  set value(n: number) { this._v = n; }
}

function first<T>(arr: T[]): T | undefined {
  return arr[0];
}

function isString(v: unknown): v is string {
  return typeof v === "string";
}

function fail(msg: string): never {
  throw new Error(msg);
}

declare module "my-legacy" {
  export function run(): void;
}
